  1 import Foundation
  2 import os
  3 
  4 public actor CodexConnector: UsageConnector {
  5     nonisolated public let vendor: Vendor = .codex
  6 
  7     private enum IdentitySource: String {
  8         case responseBody = "response_body"
  9         case credentials = "credentials"
 10         case cache = "cache"
 11     }
 12 
 13     private let auth: CodexAuthProviding
 14     private let logger: FileLogger
 15     private let session: URLSession
 16 
 17     // Thread-safe email cache readable from nonisolated resolveActiveAccount()
 18     // without blocking the cooperative thread pool.
 19     private let _cachedEmail = OSAllocatedUnfairLock<AccountEmail?>(initialState: nil)
 20     private var lastKnownMetrics: [UsageMetric] = []
 21 
 22     // Fixed window durations (Codex policy mirrors Claude's windows)
 23     private static let sessionWindowMinutes = DurationMinutes(rawValue: 300)
 24     private static let weeklyWindowMinutes = DurationMinutes(rawValue: 10080)
 25     // Codex credit pool size per the current plan definition
 26     private static let creditPoolTotal: Double = 1000
 27 
 28     // Known-valid literal — force-unwrap is safe here
 29     private static let apiURL = URL(string: "https://chatgpt.com/backend-api/wham/usage")! // known-valid literal
 30 
 31     // Actor-isolated: safe without nonisolated(unsafe) since all access is on the actor
 32     private let isoFormatter: ISO8601DateFormatter = {
 33         let f = ISO8601DateFormatter()
 34         f.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
 35         return f
 36     }()
 37 
 38     public init(
 39         auth: CodexAuthProviding = CodexAuth(),
 40         logger: FileLogger = Loggers.codex,
 41         session: URLSession = .shared
 42     ) {
 43         self.auth = auth
 44         self.logger = logger
 45         self.session = session
 46     }
 47 
 48     // MARK: - UsageConnector
 49 
 50     nonisolated public func resolveActiveAccount() -> AccountEmail? {
 51         _cachedEmail.withLock { $0 }
 52     }
 53 
 54     /// Clears the cached email so the next `fetchUsages()` call resolves a fresh email
 55     /// from the API response. Called by the account monitor on account_id changes.
 56     public func invalidateEmailCache() {
 57         _cachedEmail.withLock { $0 = nil }
 58         logger.log(.info, "Codex email cache invalidated")
 59     }
 60 
 61     public func fetchUsages() async throws -> [VendorUsageEntry] {
 62         let credentials: CodexCredentials
 63         do {
 64             credentials = try await auth.load()
 65         } catch {
 66             logger.log(.error, "Codex credentials load failed: \(error)")
 67             return errorEntries(type: "token_error")
 68         }
 69 
 70         // Check token expiry before making any network call
 71         if let lastRefreshed = credentials.lastRefreshedAt,
 72            Date().timeIntervalSince(lastRefreshed) > CodexConstants.tokenLifetimeSeconds {
 73             logger.log(.warning, "Codex token expired (last refresh > 8 days ago) — run `codex login`")
 74             return errorEntries(type: "token_expired", credentials: credentials)
 75         }
 76 
 77         logger.log(.info, "Fetching Codex usages for accountId=\(credentials.accountId)")
 78 
 79         var request = URLRequest(url: Self.apiURL)
 80         request.setValue("Bearer \(credentials.accessToken)", forHTTPHeaderField: "Authorization")
 81         request.setValue(credentials.accountId.rawValue, forHTTPHeaderField: "ChatGPT-Account-Id")
 82         // Reproduces the User-Agent used in the OpenUsage analysis to avoid bot filtering
 83         request.setValue("OpenUsage", forHTTPHeaderField: "User-Agent")
 84         request.timeoutInterval = CodexConstants.requestTimeoutSeconds
 85 
 86         let data: Data
 87         let response: URLResponse
 88         do {
 89             (data, response) = try await session.data(for: request)
 90         } catch {
 91             logger.log(.error, "Codex API request failed: \(error)")
 92             return errorEntries(type: "api_error", credentials: credentials)
 93         }
 94 
 95         let httpResponse = response as? HTTPURLResponse
 96         let httpCode = httpResponse?.statusCode ?? -1
 97         logger.log(.info, "Codex API response: HTTP \(httpCode)")
 98 
 99         if httpCode == 401 {
100             logger.log(.warning, "Codex API returned HTTP 401 — token expired or revoked")
101             return errorEntries(type: "token_expired", credentials: credentials)
102         }
103 
104         if httpCode == 429 {
105             let body = String(data: data, encoding: .utf8) ?? "<non-UTF8 body, \(data.count) bytes>"
106             logger.log(.warning, "Codex API rate-limited (HTTP 429): \(body)")
107             return errorEntries(
108                 type: "http_429",
109                 credentials: credentials,
110                 isActive: true,
111                 preservedMetrics: lastKnownMetrics
112             )
113         }
114 
115         guard let http = httpResponse, http.statusCode == 200 else {
116             logger.log(.error, "Codex API returned HTTP \(httpCode)")
117             return errorEntries(type: "http_\(httpCode)", credentials: credentials)
118         }
119 
120         logger.log(.debug, "Codex API payload: \(Self.maskedPayload(data))")
121 
122         do {
123             let (metrics, emailFromResponse) = try parseAPIResponse(data, httpResponse: http)
124             guard let (account, source) = resolvePersistedAccount(
125                 responseEmail: emailFromResponse,
126                 credentials: credentials
127             ) else {
128                 logger.log(
129                     .warning,
130                     "Codex identity_unresolved during success response for accountId=\(credentials.accountId) — no usage entry written"
131                 )
132                 return []
133             }
134             lastKnownMetrics = metrics
135             logger.log(
136                 .info,
137                 "Codex fetched \(metrics.count) metric(s) for account=\(account) via \(source.rawValue)"
138             )
139             return [VendorUsageEntry(
140                 vendor: vendor,
141                 account: account,
142                 isActive: true,
143                 lastAcquiredOn: ISODate(date: Date()),
144                 lastError: nil,
145                 metrics: metrics
146             )]
147         } catch {
148             logger.log(.error, "Codex response parse failed: \(error)")
149             logger.log(.warning, "Codex failed payload dump: \(Self.maskedPayload(data))")
150             return errorEntries(type: "parse_error", credentials: credentials)
151         }
152     }
153 
154     // MARK: - Response parsing
155 
156     private func parseAPIResponse(_ data: Data, httpResponse: HTTPURLResponse) throws -> ([UsageMetric], AccountEmail?) {
157         let jsonObject = try JSONSerialization.jsonObject(with: data)
158         guard let json = jsonObject as? [String: Any] else {
159             throw CodexConnectorError.unexpectedAPIFormat(receivedKeys: [])
160         }
161 
162         let email = normalizedEmail(json["email"] as? String)
163         var metrics: [UsageMetric] = []
164 
165         // Primary and secondary rate-limit windows
166         let rateLimit = json["rate_limit"] as? [String: Any]
167         if let window = rateLimit?["primary_window"] as? [String: Any],
168            let w = extractWindow(from: window, fallbackDuration: Self.sessionWindowMinutes) {
169             metrics.append(.timeWindow(name: "Session (5h)", resetAt: w.resetAt, windowDuration: w.duration, usagePercent: w.percent))
170         }
171         if let window = rateLimit?["secondary_window"] as? [String: Any],
172            let w = extractWindow(from: window, fallbackDuration: Self.weeklyWindowMinutes) {
173             metrics.append(.timeWindow(name: "Weekly (7d)", resetAt: w.resetAt, windowDuration: w.duration, usagePercent: w.percent))
174         }
175 
176         // Code review rate limit (optional — absent on plans without code review)
177         let codeReviewRateLimit = json["code_review_rate_limit"] as? [String: Any]
178         if let window = codeReviewRateLimit?["primary_window"] as? [String: Any],
179            let w = extractWindow(from: window, fallbackDuration: Self.weeklyWindowMinutes) {
180             metrics.append(.timeWindow(name: "Code Review (7d)", resetAt: w.resetAt, windowDuration: w.duration, usagePercent: w.percent))
181         }
182 
183         // Per-model additional rate limits (e.g. Spark plan with per-model quotas)
184         let additionalRateLimits = json["additional_rate_limits"] as? [[String: Any]] ?? []
185         for limitEntry in additionalRateLimits {
186             guard let limitName = limitEntry["limit_name"] as? String else { continue }
187             let limitRateLimit = limitEntry["rate_limit"] as? [String: Any]
188             if let window = limitRateLimit?["primary_window"] as? [String: Any],
189                let w = extractWindow(from: window, fallbackDuration: Self.sessionWindowMinutes) {
190                 metrics.append(.timeWindow(name: "\(limitName) (5h)", resetAt: w.resetAt, windowDuration: w.duration, usagePercent: w.percent))
191             }
192             if let window = limitRateLimit?["secondary_window"] as? [String: Any],
193                let w = extractWindow(from: window, fallbackDuration: Self.weeklyWindowMinutes) {
194                 metrics.append(.timeWindow(name: "\(limitName) Weekly (7d)", resetAt: w.resetAt, windowDuration: w.duration, usagePercent: w.percent))
195             }
196         }
197 
198         // Credits: body-first, header as fallback
199         let credits = json["credits"] as? [String: Any]
200         let hasCredits = credits?["has_credits"] as? Bool ?? false
201         if hasCredits, let balance = credits?["balance"] as? Double, balance >= 0 {
202             // balance is the remaining allowance; clamp to avoid negative values if total exceeds the assumed pool
203             metrics.append(.payAsYouGo(name: "Credits used", currentAmount: max(0, Self.creditPoolTotal - balance), currency: "credits"))
204         } else if let headerValue = httpResponse.value(forHTTPHeaderField: "x-codex-credits-balance"),
205                   let balance = Double(headerValue), balance >= 0 {
206             metrics.append(.payAsYouGo(name: "Credits used", currentAmount: max(0, Self.creditPoolTotal - balance), currency: "credits"))
207         }
208 
209         if metrics.isEmpty, json["rate_limit"] == nil, additionalRateLimits.isEmpty {
210             logger.log(.warning, "No known usage window in Codex payload — top-level keys: \(Array(json.keys))")
211             throw CodexConnectorError.unexpectedAPIFormat(receivedKeys: Array(json.keys))
212         }
213 
214         return (metrics, email)
215     }
216 
217     // MARK: - Window extraction
218 
219     private struct WindowValues {
220         let percent: UsagePercent
221         let resetAt: ISODate?
222         let duration: DurationMinutes
223     }
224 
225     private func extractWindow(from window: [String: Any], fallbackDuration: DurationMinutes) -> WindowValues? {
226         guard let usedPercent = window["used_percent"] as? Double else {
227             logger.log(.debug, "Window block missing used_percent — skipped")
228             return nil
229         }
230         let resetAt: ISODate?
231         if let epochSecs = window["reset_at"] as? Double, epochSecs > 0 {
232             resetAt = ISODate(date: Date(timeIntervalSince1970: epochSecs))
233         } else {
234             resetAt = nil
235         }
236         let duration: DurationMinutes
237         if let secs = window["limit_window_seconds"] as? Double, secs > 0 {
238             duration = DurationMinutes(rawValue: Int(secs) / 60)
239         } else {
240             duration = fallbackDuration
241         }
242         return WindowValues(
243             percent: UsagePercent(rawValue: Int(usedPercent.rounded())),
244             resetAt: resetAt,
245             duration: duration
246         )
247     }
248 
249     // MARK: - Payload masking
250 
251     private static let sensitiveKeyPatterns = ["token", "key", "secret", "password", "email", "credential"]
252 
253     static func maskedPayload(_ data: Data) -> String {
254         guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
255             return "<non-JSON, \(data.count) bytes>"
256         }
257         let masked = maskSensitiveFields(json)
258         guard let out = try? JSONSerialization.data(withJSONObject: masked, options: [.sortedKeys]),
259               let str = String(data: out, encoding: .utf8) else {
260             return "<serialization failed>"
261         }
262         return str
263     }
264 
265     static func maskSensitiveFields(_ dict: [String: Any]) -> [String: Any] {
266         var result: [String: Any] = [:]
267         for (key, value) in dict {
268             let lower = key.lowercased()
269             if sensitiveKeyPatterns.contains(where: { lower.contains($0) }) {
270                 result[key] = "***"
271             } else if let nested = value as? [String: Any] {
272                 result[key] = maskSensitiveFields(nested)
273             } else if let array = value as? [[String: Any]] {
274                 result[key] = array.map { maskSensitiveFields($0) }
275             } else {
276                 result[key] = value
277             }
278         }
279         return result
280     }
281 
282     // MARK: - Helpers
283 
284     private func resolvePersistedAccount(
285         responseEmail: AccountEmail? = nil,
286         credentials: CodexCredentials? = nil
287     ) -> (AccountEmail, IdentitySource)? {
288         if let responseEmail {
289             _cachedEmail.withLock { $0 = responseEmail }
290             return (responseEmail, .responseBody)
291         }
292         if let accountEmail = credentials?.accountEmail {
293             _cachedEmail.withLock { $0 = accountEmail }
294             return (accountEmail, .credentials)
295         }
296         if let cached = _cachedEmail.withLock({ $0 }) {
297             return (cached, .cache)
298         }
299         return nil
300     }
301 
302     private func errorEntries(
303         type: String,
304         credentials: CodexCredentials? = nil,
305         isActive: Bool = false,
306         preservedMetrics: [UsageMetric] = []
307     ) -> [VendorUsageEntry] {
308         guard let (account, source) = resolvePersistedAccount(credentials: credentials) else {
309             let accountId = credentials?.accountId.rawValue ?? "<unavailable>"
310             logger.log(.warning, "Codex identity_unresolved during \(type) for accountId=\(accountId) — no usage entry written")
311             return []
312         }
313         logger.log(.debug, "Codex resolved account=\(account) via \(source.rawValue) for \(type)")
314         return [errorEntry(account: account, type: type, isActive: isActive, preservedMetrics: preservedMetrics)]
315     }
316 
317     private func normalizedEmail(_ rawValue: String?) -> AccountEmail? {
318         guard let rawValue else { return nil }
319         let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
320         guard !trimmed.isEmpty else { return nil }
321         return AccountEmail(rawValue: trimmed)
322     }
323 
324     private func errorEntry(account: AccountEmail, type: String, isActive: Bool = false, preservedMetrics: [UsageMetric] = []) -> VendorUsageEntry {
325         VendorUsageEntry(
326             vendor: vendor,
327             account: account,
328             isActive: isActive,
329             lastAcquiredOn: nil,
330             lastError: UsageError(timestamp: ISODate(date: Date()), type: type),
331             metrics: preservedMetrics
332         )
333     }
334 }
335 
336 public enum CodexConnectorError: Error, CustomStringConvertible {
337     case unexpectedAPIFormat(receivedKeys: [String])
338 
339     public var description: String {
340         switch self {
341         case let .unexpectedAPIFormat(keys):
342             "Codex API response does not match expected format — top-level keys: \(keys)"
343         }
344     }
345 }

