237         if let secs = window["limit_window_seconds"] as? Double, secs > 0 {
238             duration = DurationMinutes(rawValue: Int(secs) / 60)
239         } else {
240             duration = fallbackDuration
241         }
242         return WindowValues(
243             percent: UsagePercent(rawValue: Int(usedPercent.rounded())),
244             resetAt: resetAt,
245             duration: duration
246         )
247     }
248 
249     // MARK: - Payload masking
250 
251     private static let sensitiveKeyPatterns = ["token", "key", "secret", "password", "email", "credential"]
252 
253     static func maskedPayload(_ data: Data) -> String {
254         guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
255             return "<non-JSON, \(data.count) bytes>"
256         }
257         let masked = maskSensitiveFields(json)
258         guard let out = try? JSONSerialization.data(withJSONObject: masked, options: [.sortedKeys]),
259               let str = String(data: out, encoding: .utf8) else {
260             return "<serialization failed>"
261         }
262         return str
263     }
264 
265     static func maskSensitiveFields(_ dict: [String: Any]) -> [String: Any] {
266         var result: [String: Any] = [:]
267         for (key, value) in dict {
268             let lower = key.lowercased()
269             if sensitiveKeyPatterns.contains(where: { lower.contains($0) }) {
270                 result[key] = "***"
271             } else if let nested = value as? [String: Any] {
272                 result[key] = maskSensitiveFields(nested)
273             } else if let array = value as? [[String: Any]] {
274                 result[key] = array.map { maskSensitiveFields($0) }
275             } else {
276                 result[key] = value
277             }
278         }
279         return result
280     }
281 
282     // MARK: - Helpers
283 
284     private func resolvePersistedAccount(
285         responseEmail: AccountEmail? = nil,
286         credentials: CodexCredentials? = nil
287     ) -> (AccountEmail, IdentitySource)? {
288         if let responseEmail {
289             _cachedEmail.withLock { $0 = responseEmail }
290             return (responseEmail, .responseBody)
291         }
292         if let accountEmail = credentials?.accountEmail {
293             _cachedEmail.withLock { $0 = accountEmail }
294             return (accountEmail, .credentials)
295         }
296         if let cached = _cachedEmail.withLock({ $0 }) {
297             return (cached, .cache)
298         }
299         return nil
300     }
301 
302     private func errorEntries(
303         type: String,
304         credentials: CodexCredentials? = nil,
305         isActive: Bool = false,
306         preservedMetrics: [UsageMetric] = []
307     ) -> [VendorUsageEntry] {
308         guard let (account, source) = resolvePersistedAccount(credentials: credentials) else {
309             let accountId = credentials?.accountId.rawValue ?? "<unavailable>"
310             logger.log(.warning, "Codex identity_unresolved during \(type) for accountId=\(accountId) — no usage entry written")
311             return []
312         }
313         logger.log(.debug, "Codex resolved account=\(account) via \(source.rawValue) for \(type)")
314         return [errorEntry(account: account, type: type, isActive: isActive, preservedMetrics: preservedMetrics)]
315     }
316 
317     private func normalizedEmail(_ rawValue: String?) -> AccountEmail? {
318         guard let rawValue else { return nil }
319         let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
320         guard !trimmed.isEmpty else { return nil }
321         return AccountEmail(rawValue: trimmed)
322     }
323 
324     private func errorEntry(account: AccountEmail, type: String, isActive: Bool = false, preservedMetrics: [UsageMetric] = []) -> VendorUsageEntry {
325         VendorUsageEntry(
326             vendor: vendor,
327             account: account,
328             isActive: isActive,
329             lastAcquiredOn: nil,
330             lastError: UsageError(timestamp: ISODate(date: Date()), type: type),
331             metrics: preservedMetrics
332         )
333     }
334 }
