 3 public struct ProcessExecutionResult: Sendable, Equatable {
 4     public let stdout: Data
 5     public let terminationStatus: Int32
 6     public let timedOut: Bool
 7 
 8     public init(stdout: Data, terminationStatus: Int32, timedOut: Bool) {
