15 public protocol ProcessRunning: Sendable {
16     func run(executablePath: String, arguments: [String], timeoutSeconds: Int) async throws -> ProcessExecutionResult
17 }
18 
19 public struct FoundationProcessRunner: ProcessRunning {
20     public init() {}
21 
22     public func run(executablePath: String, arguments: [String], timeoutSeconds: Int) async throws -> ProcessExecutionResult {
23         try await withCheckedThrowingContinuation { continuation in
24             DispatchQueue.global().async {
25                 let process = Process()
26                 let pipe = Pipe()
27                 let state = ProcessState()
28                 process.executableURL = URL(fileURLWithPath: executablePath)
29                 process.arguments = arguments
30                 process.standardOutput = pipe
31                 process.standardError = FileHandle.nullDevice
32                 process.terminationHandler = { _ in state.markCompleted() }
33 
34                 let timer = DispatchSource.makeTimerSource(queue: .global())
35                 timer.schedule(deadline: .now() + .seconds(timeoutSeconds))
36                 timer.setEventHandler {
37                     guard state.markTimedOutIfNotCompleted() else { return }
38                     process.terminate()
39                 }
40 
41                 do {
42                     try process.run()
43                 } catch {
44                     timer.cancel()
45                     continuation.resume(throwing: error)
46                     return
47                 }
48 
49                 timer.resume()
50                 // Read before wait to avoid pipe-buffer deadlock
51                 let raw = pipe.fileHandleForReading.readDataToEndOfFile()
52                 process.waitUntilExit()
53                 timer.cancel()
54 
55                 continuation.resume(returning: ProcessExecutionResult(
56                     stdout: raw,
57                     terminationStatus: process.terminationStatus,
58                     timedOut: state.didTimeOut
59                 ))
60             }
61         }
62     }
63 }
64 
65 private final class ProcessState: @unchecked Sendable {
66     private let lock = NSLock()
67     private var completed = false
68     private var timedOut = false
69 
70     var didTimeOut: Bool {
71         lock.lock()
72         defer { lock.unlock() }
73         return timedOut
74     }
75 
76     func markCompleted() {
77         lock.lock()
78         completed = true
79         lock.unlock()
80     }
81 
82     func markTimedOutIfNotCompleted() -> Bool {
83         lock.lock()
84         defer { lock.unlock() }
85         guard !completed else { return false }
86         timedOut = true
87         return true
88     }
89 }

